context.expression:
n = kwargs.get("node", None)
if n is None:
    return False
try:
    for parm in n.parms():
        t = parm.parmTemplate()
        if t.type() == hou.parmTemplateType.Ramp and t.parmType() == hou.rampParmType.Color:
            return True
except Exception:
    pass
return False

